import { Component, OnInit } from '@angular/core';
import { RoomTransferService } from '../../services/room-transfer.service';
import { RoomService } from '../../services/room.service';
import { AuthService } from '../../services/auth.service';
import { RoomTransferRequest } from '../../models/room-transfer-request.model';
import { Room } from '../../models/room.model';

@Component({
  selector: 'app-room-transfers',
  templateUrl: './room-transfers.component.html',
  styleUrls: ['./room-transfers.component.css']
})
export class RoomTransfersComponent implements OnInit {
  requests: RoomTransferRequest[] = [];
  availableRooms: Room[] = [];
  currentUser: any;
  showForm = false;
  newRequest: RoomTransferRequest = { 
    studentId: 0, studentName: '', currentRoomId: 0, currentRoomNumber: '',
    requestedRoomId: 0, requestedRoomNumber: '', reason: '', status: 'PENDING'
  };

  constructor(
    private transferService: RoomTransferService, 
    private roomService: RoomService,
    private authService: AuthService
  ) {}

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadRequests();
    this.loadAvailableRooms();
  }

  loadRequests() {
    if (this.currentUser.role === 'STUDENT') {
      this.transferService.getTransferRequestsByStudent(this.currentUser.id).subscribe(data => this.requests = data);
    } else {
      this.transferService.getAllTransferRequests().subscribe(data => this.requests = data);
    }
  }

  loadAvailableRooms() {
    this.roomService.getAvailableRooms().subscribe(data => this.availableRooms = data);
  }

  createRequest() {
    this.newRequest.studentId = this.currentUser.id;
    this.newRequest.studentName = this.currentUser.firstName + ' ' + this.currentUser.lastName;

    const selectedRoom = this.availableRooms.find(r => r.id === this.newRequest.requestedRoomId);
    if (selectedRoom) {
      this.newRequest.requestedRoomNumber = selectedRoom.roomNumber;
    }

    this.transferService.createTransferRequest(this.newRequest).subscribe({
      next: () => {
        this.loadRequests();
        this.showForm = false;
        alert('Transfer request submitted!');
      },
      error: (err) => alert('Error creating request: ' + err.message)
    });
  }

  approveRequest(req: RoomTransferRequest) {
    if(confirm('Approve this room transfer?')) {
      const update = {
        ...req,
        status: 'APPROVED',
        approverName: this.currentUser.firstName + ' ' + this.currentUser.lastName
      };
      this.transferService.updateTransferRequest(req.id!, update).subscribe({
        next: () => { alert('Approved and room assigned!'); this.loadRequests(); },
        error: (err) => alert('Error approving')
      });
    }
  }

  rejectRequest(req: RoomTransferRequest) {
    const remarks = prompt('Rejection reason:');
    if(remarks) {
      const update = {
        ...req,
        status: 'REJECTED',
        approverName: this.currentUser.firstName + ' ' + this.currentUser.lastName,
        remarks: remarks
      };
      this.transferService.updateTransferRequest(req.id!, update).subscribe({
        next: () => { alert('Rejected!'); this.loadRequests(); },
        error: (err) => alert('Error rejecting')
      });
    }
  }

  deleteRequest(id: number) {
    if(confirm('Delete?')) {
      this.transferService.deleteTransferRequest(id).subscribe(() => { alert('Deleted!'); this.loadRequests(); });
    }
  }

  canApprove(): boolean { return this.currentUser.role === 'ADMIN' || this.currentUser.role === 'WARDEN'; }
  canDelete(): boolean { return this.currentUser.role === 'ADMIN'; }
}
<div class="content-wrapper">
  <div class="container-fluid">
    <div class="d-flex justify-content-between mb-4">
      <h2>Room Transfer Requests</h2>
      <button class="btn btn-primary" *ngIf="currentUser?.role === 'STUDENT'" (click)="showForm = !showForm">
        {{ showForm ? 'Cancel' : '+ New Request' }}
      </button>
    </div>

    <div *ngIf="showForm" class="card mb-4">
      <div class="card-body">
        <form (ngSubmit)="createRequest()">
          <div class="row">
            <div class="col-md-6 mb-3">
              <label>Current Room Number</label>
              <input type="text" class="form-control" [(ngModel)]="newRequest.currentRoomNumber" name="currentRoom" required>
            </div>
            <div class="col-md-6 mb-3">
              <label>Current Room ID</label>
              <input type="number" class="form-control" [(ngModel)]="newRequest.currentRoomId" name="currentRoomId" required>
            </div>
          </div>
          <div class="mb-3">
            <label>Requested Room</label>
            <select class="form-control" [(ngModel)]="newRequest.requestedRoomId" name="requestedRoom" required>
              <option value="">Select Room</option>
              <option *ngFor="let room of availableRooms" [value]="room.id">
                {{ room.roomNumber }} - {{ room.roomType }} ({{ room.availableBeds }} beds available)
              </option>
            </select>
          </div>
          <div class="mb-3">
            <label>Reason</label>
            <textarea class="form-control" [(ngModel)]="newRequest.reason" name="reason" rows="3" required></textarea>
          </div>
          <button type="submit" class="btn btn-success">Submit Request</button>
        </form>
      </div>
    </div>

    <div class="table-responsive">
      <table class="table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Student</th>
            <th>Current Room</th>
            <th>Requested Room</th>
            <th>Reason</th>
            <th>Status</th>
            <th>Approver</th>
            <th *ngIf="canApprove() || canDelete()">Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let req of requests">
            <td>{{ req.id }}</td>
            <td>{{ req.studentName }}</td>
            <td>{{ req.currentRoomNumber }}</td>
            <td>{{ req.requestedRoomNumber }}</td>
            <td>{{ req.reason }}</td>
            <td><span class="badge" [ngClass]="{'bg-success': req.status === 'APPROVED', 'bg-danger': req.status === 'REJECTED', 'bg-warning': req.status === 'PENDING'}">{{ req.status }}</span></td>
            <td>{{ req.approverName || '-' }}</td>
            <td *ngIf="canApprove() || canDelete()">
              <button class="btn btn-sm btn-success me-1" *ngIf="canApprove() && req.status === 'PENDING'" (click)="approveRequest(req)">Approve</button>
              <button class="btn btn-sm btn-danger me-1" *ngIf="canApprove() && req.status === 'PENDING'" (click)="rejectRequest(req)">Reject</button>
              <button class="btn btn-sm btn-danger" *ngIf="canDelete()" (click)="deleteRequest(req.id!)">Delete</button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
